import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

import org.owasp.encoder.Encode;

public class InputHandlerServlet extends HttpServlet {
    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");
        String sanitizedInput = Encode.forHtml(userInput); // Sanitize user input

        String output = "Hello, " + sanitizedInput + "!";

        response.setContentType("text/html");
        PrintWriter out = response.getWriter();

        out.println("<html>");
        out.println("<head><title>Secure Output</title></head>");
        out.println("<body>");
        out.println("<h1>Welcome</h1>");
        out.println("<p>" + output + "</p>");
        out.println("</body></html>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
